    handleError(error, res, 'USERS_FETCH_ERROR');
  }
});

// ========== ERROR HANDLING ==========

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', {
    message: err.message,
    path: req.path,
    method: req.method,
    timestamp: new Date().toISOString()
  });

  // Don't expose stack trace to client
  res.status(err.status || 500).json({
    error: 'Internal server error',
    code: err.code || 'INTERNAL_ERROR',
    // Only include details in development
    ...(process.env.NODE_ENV === 'development' && { details: err.message })
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({
    error: 'Not found',
    code: 'NOT_FOUND',
    path: req.path
  });
});

// ========== ERROR HANDLER UTILITY ==========

function handleError(error, res, errorCode) {
  console.error(`Error [${errorCode}]:`, error);

  res.status(500).json({
    error: 'An error occurred processing your request',
    code: errorCode
  });
}

// ========== SERVER START ==========

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

### **🛡️ Key Security Enhancements**

| Issue | Solution |
|-------|----------|
| Missing headers | `helmet` adds security headers (CSP, X-Frame-Options, etc.) |
| No input validation | Query parameters validated with `validator` library |
| DoS vulnerability | `express-rate-limit` prevents request flooding |
| Error exposure | Stack traces not sent to clients; logged server-side only |
| Request bombing | Body size limited to 1KB |
| SQL injection | Query parameters properly validated and sanitized |
| Information leakage | Sensitive details hidden in production |

### **📦 Required Dependencies**

```bash
npm install helmet express-rate-limit validator
```

### **🔒 Additional Recommendations**

1. **Environment Variables**: Store port, secrets in `.env`
2. **Logging**: Use structured logging (Winston, Pino)
3. **CORS**: Add `cors` middleware if needed
4. **HTTPS**: Use TLS in production
5. **Authentication**: Add JWT or session-based auth for protected endpoints
6. **Database**: Use parameterized queries; never concat SQL
7. **Testing**: Add security-focused unit tests

