// Secure application with proper error handling and input validation
// Implements security best practices

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { body, query, validationResult } = require('express-validator');
const logger = require('morgan');

const app = express();
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// ============ SECURITY MIDDLEWARE ============

// 1. Helmet - Set security HTTP headers
app.use(helmet());

// 2. Request Rate Limiting - Prevent DoS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
});

// Apply rate limiting to all requests
app.use(limiter);

// 3. Request Logging - Audit trail
app.use(logger(NODE_ENV === 'production' ? 'combined' : 'dev'));

// 4. JSON Body Parser with size limit - Prevent large payload attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// ============ VALIDATION HELPERS ============

// Middleware to handle validation errors
const handleValidationErrors = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      status: 'error',
      message: 'Validation failed',
      errors: errors.array().map(e => ({
        field: e.param,
        message: e.msg,
      })),
    });
  }
  next();
};

// ============ ROUTES ============

// Health Check Endpoint
app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

// Get Users Endpoint - with query parameter validation
app.get(
  '/users',
  [
    // Validate optional query parameters
    query('page')
      .optional()
      .isInt({ min: 1 })
      .withMessage('Page must be a positive integer'),
    query('limit')
      .optional()
      .isInt({ min: 1, max: 100 })
      .withMessage('Limit must be between 1 and 100'),
  ],
  handleValidationErrors,
  (req, res) => {
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;

    // Hardcoded user data (in production, this would be from a database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Pagination logic
    const startIndex = (page - 1) * limit;
    const paginatedUsers = users.slice(startIndex, startIndex + limit);

    res.json({
      status: 'success',
      data: paginatedUsers,
      pagination: {
        page,
        limit,
        total: users.length,
      },
    });
  }
);

// Example: POST endpoint with input validation
app.post(
  '/users',
  [
    // Validate request body
    body('name')
      .trim()
      .notEmpty()
      .withMessage('Name is required')
      .isLength({ min: 2, max: 50 })
      .withMessage('Name must be between 2 and 50 characters'),
    body('email')
      .trim()
      .isEmail()
      .withMessage('Invalid email address')
      .normalizeEmail(),
  ],
  handleValidationErrors,
  (req, res) => {
    try {
      const { name, email } = req.body;

      // Simulate database operation
      const newUser = {
        id: Math.floor(Math.random() * 10000),
        name,
        email,
      };

      res.status(201).json({
        status: 'success',
        message: 'User created successfully',
        data: newUser,
      });
    } catch (error) {
      // Log error internally (don't expose to client)
      console.error('Error creating user:', error);
      res.status(500).json({
        status: 'error',
        message: 'Internal server error. Please try again later.',
      });
    }
  }
);

// ============ ERROR HANDLING ============

// 404 Not Found Handler
app.use((req, res) => {
  res.status(404).json({
    status: 'error',
    message: 'Endpoint not found',
  });
});

// Global Error Handler - must be last middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't leak error details in production
  const isDevelopment = NODE_ENV === 'development';
  const statusCode = err.statusCode || 500;
  const message = isDevelopment ? err.message : 'Internal server error';

  res.status(statusCode).json({
    status: 'error',
    message,
    ...(isDevelopment && { stack: err.stack }),
  });
});

// ============ SERVER STARTUP ============

// Graceful shutdown handler
process.on('SIGTERM', () => {
  console.log('SIGTERM received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
    process.exit(0);
  });
});

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${NODE_ENV} mode`);
});

module.exports = app;

# Security Review: app.js

## Executive Summary
The current `app.js` is a basic Express server with **critical security gaps**. It lacks input validation, error handling, rate limiting, and security headers. Below are detailed findings and recommendations.

---

## Critical Vulnerabilities

### 1. ❌ No Input Validation
**Issue:** Endpoints accept any request without validating input.
- Vulnerable to injection attacks if endpoints expand to accept user input
- No type checking or sanitization

**Fix:**
```javascript
// Use express-validator for input validation
const { body, query, validationResult } = require('express-validator');

app.get('/users',
  query('page').optional().isInt({ min: 1 }),
  query('limit').optional().isInt({ min: 1, max: 100 }),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // ... rest of logic
  }
);
```

---

### 2. ❌ Missing Security Headers
**Issue:** No HTTP security headers set (no helmet).

**Vulnerable to:**
- Clickjacking attacks (missing X-Frame-Options)
- MIME type sniffing (missing X-Content-Type-Options)
- XSS attacks (missing X-XSS-Protection)

**Fix:**
```javascript
const helmet = require('helmet');
app.use(helmet());
```

---

### 3. ❌ No Rate Limiting
**Issue:** Server has no protection against DoS/brute force attacks.

**Fix:**
```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // 100 requests per windowMs
  message: 'Too many requests'
});

app.use(limiter);
```

---

### 4. ❌ No Global Error Handler
**Issue:** Unhandled exceptions will crash the server or leak sensitive information.

**Problems:**
- Stack traces exposed to clients (information disclosure)
- No logging for security audits
- No graceful error responses

**Fix:**
```javascript
// Global error handler (must be last middleware)
app.use((err, req, res, next) => {
  console.error('Error:', err);

  const isDevelopment = process.env.NODE_ENV === 'development';
  res.status(err.statusCode || 500).json({
    status: 'error',
    message: isDevelopment ? err.message : 'Internal server error',
  });
});
```

---

### 5. ❌ No HTTPS
**Issue:** Server only uses HTTP (unencrypted).

**Risk:** All data transmitted in plaintext, vulnerable to MITM attacks.

**Fix:** Use reverse proxy (nginx, AWS ALB) or Node.js HTTPS:
```javascript
const https = require('https');
const fs = require('fs');

const options = {
  key: fs.readFileSync('path/to/key.pem'),
  cert: fs.readFileSync('path/to/cert.pem')
};

https.createServer(options, app).listen(443);
```

---

## High Priority Issues

### 6. ⚠️ No CORS Configuration
**Issue:** No Cross-Origin Resource Sharing setup.

**Risk:** Could allow unauthorized cross-origin requests or deny legitimate ones.

**Fix:**
```javascript
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type']
}));
```

---

### 7. ⚠️ No Request Logging
**Issue:** No audit trail for security incidents.

**Fix:**
```javascript
const morgan = require('morgan');
app.use(morgan('combined')); // or 'dev' for development
```

---

### 8. ⚠️ Hardcoded Port
**Issue:** Port number hardcoded; no environment configuration.

**Fix:**
```javascript
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

---

### 9. ⚠️ No Payload Size Limit
**Issue:** Unbounded request size could lead to DoS via large payloads.

**Fix:**
```javascript
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));
```

---

### 10. ⚠️ No Graceful Shutdown
**Issue:** Server doesn't handle SIGTERM; connections abruptly terminated.

**Fix:**
```javascript
